</head>
<body>

    <div class="container">
        <header>
            <h1>Package Manager Migration Utility</h1>
            <p>Generate a hard-coded migration playbook based on the Engineering Report[cite: 1].</p>
        </header>

        <div class="controls">
            <div class="control-group">
                <label for="source">Migrate From:</label>
                <select id="source" onchange="updateTargetOptions()">
                    <option value="npm">npm</option>
                    <option value="yarn-classic">Yarn Classic (v1)</option>
                    <option value="yarn-berry">Yarn Berry (v2+ PnP)</option>
                    <option value="pnpm">pnpm</option>
                    <option value="bun">Bun</option>
                </select>
            </div>

            <div class="control-group">
                <label for="target">Migrate To:</label>
                <select id="target">
                    </select>
            </div>

            <button id="generate-btn" onclick="generatePlaybook()">Generate Playbook</button>
        </div>

        <div id="playbook-output">
            <div class="placeholder">Select a source and target manager to generate the migration playbook.</div>
        </div>
    </div>

    <script>
        // --- Hard-coded Playbook Matrix ---
        // This object contains the "finite technical coded details" for each migration path,
        // transcribed directly from the provided engineering report [cite: 155-319].
        const playbookMatrix = {
            "npm": {
                "pnpm": {
                    title: "Migration Playbook: npm to pnpm [cite: 162]",
                    content: `
                        <div class="info">
                            <strong>Key Consideration:</strong> This migration gains disk space efficiency and strictness[cite: 164]. 
                            The new strictness may reveal pre-existing "phantom dependency" bugs[cite: 165].
                        </div>
                        <h3>Command Sequence [cite: 166-175]</h3>
                        <pre><code><span class="comment"># 1. Remove existing node_modules to ensure a clean slate [cite: 169]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>

<span class="comment"># 2. Import from package-lock.json to create a pnpm-lock.yaml [cite: 171, 172]</span>
<span class="command">pnpm</span> import

<span class="comment"># 3. Remove the old npm lockfile [cite: 173]</span>
<span class="command">rm</span> <span class="path">package-lock.json</span>

<span class="comment"># 4. Install dependencies using pnpm to create the symlinked structure [cite: 174, 175]</span>
<span class="command">pnpm</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 176]</h3>
                        <div class="warning">
                            <strong>Potential Issue: "Module not found" errors[cite: 177].</strong>
                            <p>This is not a bug. It means your code was relying on a <strong>phantom dependency</strong> that npm hoisted[cite: 178].</p>
                            <strong>Resolution:</strong> Explicitly add the missing package to the \`package.json\` of the module that needs it[cite: 179].
                            <pre><code><span class="command">pnpm</span> add <span class="path">&lt;package-name&gt;</span></code></pre>
                        </div>
                        <p><strong>CI/CD Update:</strong> Your build scripts should now use <code>pnpm install --frozen-lockfile</code> instead of <code>npm ci</code>[cite: 181].</p>
                    `
                },
                "yarn-berry": {
                    title: "Migration Playbook: npm to Yarn Berry (Compatibility Mode) [cite: 182, 185]",
                    content: `
                        <div class="info">
                            <strong>Key Consideration:</strong> This playbook migrates to Yarn Berry but configures it to use a 
                            <code>node_modules</code> directory for maximum compatibility with existing tools[cite: 185].
                        </div>
                        <h3>Command Sequence [cite: 186-193]</h3>
                        <pre><code><span class="comment"># 1. Enable Corepack (the standard Node.js package manager manager) [cite: 187]</span>
<span class="command">corepack</span> enable

<span class="comment"># 2. Set the project to use the Yarn Berry version [cite: 188]</span>
<span class="comment"># This creates .yarn/releases and .yarnrc.yml [cite: 189]</span>
<span class="command">yarn</span> set version berry

<span class="comment"># 3. *** CRITICAL STEP ***</span>
<span class="comment"># Manually edit the newly created .yarnrc.yml file: [cite: 190]</span>
<span class="comment"># Add this line to force a node_modules linker: [cite: 191]</span>
<span class="path">nodeLinker: node-modules</span>

<span class="comment"># 4. Clean npm artifacts [cite: 192]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>
<span class="command">rm</span> <span class="path">package-lock.json</span>

<span class="comment"># 5. Install dependencies with Yarn [cite: 193]</span>
<span class="command">yarn</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 194]</h3>
                        <div class="warning">
                            <strong>Configuration Translation:</strong> Yarn Berry <strong>deliberately ignores</strong> <code>.npmrc</code> files[cite: 142].
                            <p>You must manually translate any settings (like private registry URLs or auth tokens) 
                            from <code>.npmrc</code> into the YAML syntax of <code>.yarnrc.yml</code>[cite: 195].</p>
                        </div>
                    `
                },
                "bun": {
                    title: "Migration Playbook: npm to Bun [cite: 197]",
                    content: `
                        <div class="info">
                            <strong>Key Consideration:</strong> This is a "drop-in" replacement focused on performance[cite: 198]. 
                            The primary issue you will face is how Bun handles lifecycle scripts[cite: 206].
                        </div>
                        <h3>Command Sequence [cite: 200-204]</h3>
                        <pre><code><span class="comment"># 1. Clean all npm-generated files [cite: 202]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>
<span class="command">rm</span> <span class="path">package-lock.json</span>

<span class="comment"># 2. Install dependencies with Bun [cite: 203]</span>
<span class="comment"># Bun reads package.json and generates a bun.lockb file [cite: 204]</span>
<span class="command">bun</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 205]</h3>
                        <div class="warning">
                            <strong>Potential Issue: <code>postinstall</code> scripts fail[cite: 206].</strong>
                            <p>For security, Bun <strong>does not run postinstall scripts by default</strong>[cite: 207].</p>
                            <strong>Resolution:</strong> You must explicitly trust packages that need <code>postinstall</code> (e.g., <code>prisma</code>) 
                            by adding them to <code>trustedDependencies</code> in your <code>package.json</code>[cite: 208].
                            <pre><code><span class="comment">// package.json</span>
{
  <span class="keyword">"trustedDependencies"</span>: [
    <span class="path">"prisma"</span>,
    <span class="path">"another-package"</span>
  ]
}</code></pre>
                            <p>Also, thoroughly test any code using native Node.js APIs (e.g., <code>crypto</code>, <code>tls</code>) for compatibility[cite: 209].</p>
                        </div>
                    `
                }
            },
            "yarn-classic": {
                "pnpm": {
                    title: "Migration Playbook: Yarn Classic (v1) to pnpm [cite: 212]",
                    content: `
                        <div class="info">
                            <strong>Key Consideration:</strong> This path is very similar to \`npm -> pnpm\`[cite: 213]. 
                            pnpm can import from <code>yarn.lock</code> [cite: 214] and will enforce strictness, 
                            likely revealing phantom dependencies[cite: 223].
                        </div>
                        <h3>Command Sequence [cite: 215-220]</h3>
                        <pre><code><span class="comment"># 1. Clean Yarn Classic artifacts [cite: 217]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>

<span class="comment"># 2. Import from yarn.lock to create a pnpm-lock.yaml [cite: 218, 50]</span>
<span class="command">pnpm</span> import

<span class="comment"># 3. Remove the old Yarn lockfile [cite: 219]</span>
<span class="command">rm</span> <span class="path">yarn.lock</span>

<span class="comment"># 4. Install dependencies using pnpm [cite: 220]</span>
<span class="command">pnpm</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 221]</h3>
                        <div class="warning">
                            <strong>Potential Issue: "Module not found" errors.</strong>
                            <p>This is expected. It means your code was relying on a <strong>phantom dependency</strong> 
                            that Yarn Classic's hoisted <code>node_modules</code> was hiding[cite: 223].</p>
                            <strong>Resolution:</strong> Explicitly add the missing package[cite: 179].
                            <pre><code><span class="command">pnpm</span> add <span class="path">&lt;package-name&gt;</span></code></pre>
                        </div>
                    `
                },
                "bun": {
                    title: "Migration Playbook: Yarn Classic (v1) to Bun [cite: 243]",
                     content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> This is a highly deterministic migration. Bun can read your existing 
                            <code>yarn.lock</code> file to create its <code>bun.lockb</code>, preserving your dependency resolution[cite: 244, 245].
                        </div>
                        <h3>Command Sequence [cite: 246-249]</h3>
                        <pre><code><span class="comment"># 1. Clean Yarn-specific directories [cite: 247]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>

<span class="comment"># 2. Install with Bun [cite: 248]</span>
<span class="comment"># Bun will detect yarn.lock, use it, and generate bun.lockb [cite: 248]</span>
<span class="command">bun</span> install

<span class="comment"># 3. After verifying, remove the old lockfile [cite: 249]</span>
<span class="command">rm</span> <span class="path">yarn.lock</span></code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 251]</h3>
                        <div class="warning">
                            <strong>Potential Issue: <code>postinstall</code> scripts fail[cite: 206].</strong>
                            <p>For security, Bun <strong>does not run postinstall scripts by default</strong>[cite: 207].</p>
                            <strong>Resolution:</strong> You must explicitly trust packages that need <code>postinstall</code> 
                            by adding them to <code>trustedDependencies</code> in your <code>package.json</code>[cite: 208].
                        </div>
                    \`
                }
                // Note: yarn-classic to yarn-berry is an upgrade path, not a migration.
                // Note: yarn-classic to npm is just rm yarn.lock, rm -rf node_modules, npm install.
            },
            "yarn-berry": {
                "npm": {
                    title: "Migration Playbook: Yarn Berry (PnP) to npm (The 'Ejection' Process) [cite: 224]",
                    content: \`
                        <div class="warning">
                            <strong>Critical Warning:</strong> This is a complex "ejection" from PnP, not a simple migration[cite: 225]. 
                            This is a <strong>destructive migration</strong>[cite: 239]. The dependency graph from 
                            <code>yarn.lock</code> will be discarded, and npm will perform a fresh resolution, 
                            which may install different versions of transitive dependencies[cite: 240, 241].
                        </div>
                        <h3>Command Sequence [cite: 228-237]</h3>
                        <pre><code><span class="comment"># 1. *** CRITICAL FIRST STEP ***</span>
<span class="comment"># Reconfigure Yarn to generate a node_modules folder. [cite: 229]</span>
<span class="comment"># Edit .yarnrc.yml and set the linker:</span>
<span class="path">nodeLinker: node-modules</span>

<span class="comment"># 2. Clean all PnP-specific artifacts [cite: 230]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">.yarn/cache</span> <span class="path">.yarn/unplugged</span> <span class="path">.pnp.cjs</span>

<span class="comment"># 3. Run Yarn one last time to generate a traditional node_modules [cite: 231, 232]</span>
<span class="command">yarn</span> install

<span class="comment"># 4. Now that a node_modules exists, remove ALL Yarn files [cite: 234, 235]</span>
<span class="command">rm</span> <span class="path">.yarnrc.yml</span>
<span class="command">rm</span> <span class="path">yarn.lock</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">.yarn</span>

<span class="comment"># 5. Finally, let npm take over [cite: 236]</span>
<span class="comment"># This creates a package-lock.json and overwrites node_modules [cite: 237]</span>
<span class="command">npm</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting</h3>
                        <p>Thoroughly test your entire application. Subtle bugs may be introduced by 
                        different resolved versions of transitive dependencies[cite: 241].</p>
                    \`
                }
                // Note: yarn-berry to pnpm/bun would follow a similar "ejection" process.
            },
            "pnpm": {
                "npm": {
                    title: "Migration Playbook: pnpm to npm [cite: 255]",
                    content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> You are sacrificing disk efficiency and correctness[cite: 253]. 
                            Your project will now be susceptible to phantom dependency bugs that pnpm was preventing[cite: 263].
                        </div>
                        <h3>Command Sequence [cite: 258-261]</h3>
                        <pre><code><span class="comment"># 1. Clean all pnpm-generated files and directories [cite: 259]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>
<span class="command">rm</span> <span class="path">pnpm-lock.yaml</span>
<span class="comment"># Also remove pnpm-workspace.yaml if it exists [cite: 259]</span>
<span class="command">rm</span> <span class="path">pnpm-workspace.yaml</span>

<span class="comment"># 2. Install with npm [cite: 260]</span>
<span class="comment"># This generates a flat node_modules and a package-lock.json [cite: 260]</span>
<span class="command">npm</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 262]</h3>
                        <div class="warning">
                            <strong>Risk: Latent Bugs Activated.</strong>
                            <p>Code that was previously failing may now "work" because it's implicitly 
                            accessing a phantom dependency[cite: 264]. A strict code audit or linter setup is 
                            recommended to find these[cite: 265].</p>
                            <p>Expect a noticeable increase in disk space usage[cite: 266].</p>
                        </div>
                    \`
                },
                "yarn-berry": {
                    title: "Migration Playbook: pnpm to Yarn Berry (PnP) [cite: 267]",
                    content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> This trades pnpm's disk efficiency for Yarn's 
                            CI speed (Zero-Installs)[cite: 268]. This is a high-effort migration due to 
                            PnP's tooling compatibility requirements[cite: 277].
                        </div>
                        <h3>Command Sequence (Direct) [cite: 271-275]</h3>
                        <pre><code><span class="comment"># 1. Clean all pnpm artifacts [cite: 272]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>
<span class="command">rm</span> <span class="path">pnpm-lock.yaml</span>
<span class="command">rm</span> <span class="path">pnpm-workspace.yaml</span>

<span class="comment"># 2. Enable Corepack and set up Yarn Berry [cite: 273]</span>
<span class="command">corepack</span> enable
<span class="command">yarn</span> set version berry

<span class="comment"># 3. Install with Yarn [cite: 274]</span>
<span class="comment"># This performs a fresh resolution and creates PnP artifacts [cite: 274]</span>
<span class="command">yarn</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 276]</h3>
                        <div class="warning">
                            <strong>Primary Challenge: Tooling Compatibility[cite: 277].</strong>
                            <p>Your IDE (e.g., VS Code), TypeScript, ESLint, and bundlers may break[cite: 56]. 
                            You must install editor SDKs (<code>yarn dlx @yarnpkg/sdks vscode</code>) 
                            or PnP-specific plugins to make them compatible[cite: 278].</p>
                        </div>
                    \`
                },
                "bun": {
                    title: "Migration Playbook: pnpm to Bun [cite: 280]",
                    content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> This is a smooth, deterministic migration between two 
                            symlink-based managers[cite: 280]. Bun can read <code>pnpm-lock.yaml</code>[cite: 280].
                        </div>
                        <h3>Command Sequence [cite: 281-285]</h3>
                        <pre><code><span class="comment"># 1. Clean the pnpm-generated node_modules [cite: 282]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>

<span class="comment"># 2. Install with Bun [cite: 283]</span>
<span class="comment"># Bun will detect pnpm-lock.yaml and generate bun.lockb [cite: 283]</span>
<span class="command">bun</span> install

<span class="comment"># 3. After verifying, remove pnpm artifacts [cite: 285]</span>
<span class="command">rm</span> <span class="path">pnpm-lock.yaml</span>
<span class="command">rm</span> <span class="path">pnpm-workspace.yaml</span></code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 287]</h3>
                        <div class="warning">
                            <strong>Potential Issues:</strong> The same as other Bun migrations:
                            <ol>
                                <li><strong><code>postinstall</code> scripts</strong> will not run by default[cite: 207]. Add them to <code>trustedDependencies</code> in <code>package.json</code>[cite: 208].</li>
                                <li><strong>Node.js API compatibility</strong> must be thoroughly tested[cite: 209].</li>
                            </ol>
                        </div>
                    \`
                }
            },
            "bun": {
                "npm": {
                    title: "Migration Playbook: Bun to npm [cite: 290]",
                    content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> You are prioritizing ecosystem compatibility over raw performance[cite: 291, 292]. 
                            This is a runtime change, not just a package manager change[cite: 300].
                        </div>
                        <h3>Command Sequence [cite: 293-295]</h3>
                        <pre><code><span class="comment"># 1. Clean all Bun-specific files [cite: 294]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>
<span class="command">rm</span> <span class="path">bun.lockb</span>

<span class="comment"># 2. Install with npm [cite: 295]</span>
<span class="comment"># This generates a package-lock.json and hoisted node_modules [cite: 295]</span>
<span class="command">npm</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting</h3>
                        <div class="warning">
                            <strong>Critical Runtime Change[cite: 300]:</strong>
                            <p>You must update all scripts in <code>package.json</code> and CI/CD files to use 
                            <strong><code>node</code></strong> instead of <strong><code>bun</code></strong>[cite: 301, 302].</p>
                            <pre><code><span class="comment">// package.json "scripts"</span>
<span class="path">"start"</span>: <span class="keyword">"node index.js"</span> <span class="comment">// (not "bun start" or "bun index.js")</span></code></pre>
                            <p>Also, <code>postinstall</code> scripts will now run automatically, which was not the 
                            default behavior in Bun[cite: 298, 299].</p>
                        </div>
                    \`
                },
                "pnpm": {
                    title: "Migration Playbook: Bun to pnpm [cite: 304]",
                    content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> A low-risk migration, as both tools use a strict, 
                            symlinked <code>node_modules</code> structure[cite: 309]. The main change is switching 
                            from the Bun runtime back to Node.js[cite: 310].
                        </div>
                        <h3>Command Sequence [cite: 305-307]</h3>
                        <pre><code><span class="comment"># 1. Clean Bun-specific files [cite: 306]</span>
<span class="command">rm</span> <span class="keyword">-rf</span> <span class="path">node_modules</span>
<span class="command">rm</span> <span class="path">bun.lockb</span>

<span class="comment"># 2. Install with pnpm [cite: 307]</span>
<span class="command">pnpm</span> install</code></pre>

                        <h3>Post-Migration Validation & Troubleshooting [cite: 310]</h3>
                        <div class="warning">
                            <strong>Runtime Change:</strong>
                            <p>Remember to update all <code>package.json</code> and CI/CD scripts to use 
                            <strong><code>node</code></strong> (run via <code>pnpm run ...</code>) instead of 
                            <strong><code>bun</code></strong>[cite: 310].</p>
                        </div>
                    \`
                },
                "yarn-berry": {
                    title: "Migration Playbook: Bun to Yarn Berry (PnP) [cite: 312]",
                    content: \`
                        <div class="info">
                            <strong>Key Consideration:</strong> This is a high-effort migration that trades Bun's 
                            all-in-one speed for Yarn's specialized CI/CD features[cite: 312, 319].
